module DeepNest6Methods
  def self.write_deep_nest6(w, obj)
    count = 2
    count += 1 unless obj.addr.nil?
    w.begin_object(count)
    w.write_field("items")
    w.begin_array(obj.items.length)
    obj.items.each do |item|
      w.next_element
      IdValMethods.write_id_val(w, item)
    end
    w.end_array
    unless obj.addr.nil?
      w.write_field("addr")
      AddrMethods.write_addr(w, obj.addr)
    end
    w.write_field("coord")
    CoordMethods.write_coord(w, obj.coord)
    w.end_object
  end

  def self.decode_deep_nest6(r)
    r.begin_object
    obj = DeepNest6.new
    while r.has_next_field
      key = r.read_field_name
      if key == "items"
        tmp45 = []
        r.begin_array
        tmp45 << IdValMethods.decode_id_val(r) while r.has_next_element
        r.end_array
        obj.items = tmp45
        next
      end
      if key == "addr"
        tmp46 = nil
        if r.is_null
            r.read_null
        else
            tmp46 = AddrMethods.decode_addr(r)
        end
        obj.addr = tmp46
        next
      end
      if key == "coord" then obj.coord = CoordMethods.decode_coord(r); next; end
      r.skip
    end
    r.end_object
    obj
  end
end

