      if key == "event" then obj.event = r.read_string; next; end
      if key == "payload" then obj.payload = r.read_bytes; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

class ConfigEntry
  attr_accessor :key, :int_value, :str_value, :bool_value, :float_value

  def initialize(
    key: nil,
    int_value: nil,
    str_value: nil,
    bool_value: nil,
    float_value: nil
  )
    @key = key
    @int_value = int_value
    @str_value = str_value
    @bool_value = bool_value
    @float_value = float_value
  end
end

module ConfigEntryMethods
  def self.write_config_entry(w, obj)
    count = 1
    count += 1 unless obj.int_value.nil?
    count += 1 unless obj.str_value.nil?
    count += 1 unless obj.bool_value.nil?
    count += 1 unless obj.float_value.nil?
    w.begin_object(count)
    w.write_field("key")
    w.write_string(obj.key)
    unless obj.int_value.nil?
      w.write_field("intValue")
      w.write_int32(obj.int_value)
    end
    unless obj.str_value.nil?
      w.write_field("strValue")
      w.write_string(obj.str_value)
    end
    unless obj.bool_value.nil?
      w.write_field("boolValue")
      w.write_bool(obj.bool_value)
    end
    unless obj.float_value.nil?
      w.write_field("floatValue")
      w.write_float64(obj.float_value)
    end
    w.end_object
  end

  def self.decode_config_entry(r)
    r.begin_object
    obj = ConfigEntry.new
    while r.has_next_field
      key = r.read_field_name
      if key == "key" then obj.key = r.read_string; next; end
      if key == "intValue" then obj.int_value = r.read_int32; next; end
      if key == "strValue" then obj.str_value = r.read_string; next; end
      if key == "boolValue" then obj.bool_value = r.read_bool; next; end
      if key == "floatValue" then obj.float_value = r.read_float64; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

